import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c,e as s}from"./app-be253e4c.js";const o={},n=s(`<h1 id="chmod命令" tabindex="-1"><a class="header-anchor" href="#chmod命令" aria-hidden="true">#</a> chmod命令</h1><p><code>chmod</code>命令用来变更文件或目录的权限，文件或目录权限的控制分别以读取、写入、执行<code>3</code>种一般权限来区分，另有<code>3</code>种特殊权限可供运用。用户可以使用<code>chmod</code>指令去变更文件与目录的权限，设置方式采用文字或数字代号皆可，此外符号连接的权限无法变更，如果用户对符号连接修改权限，其改变会作用在被连接的原始文件。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> <span class="token punctuation">[</span>option<span class="token punctuation">]</span> <span class="token punctuation">[</span>ugoa<span class="token punctuation">..</span>.<span class="token punctuation">]</span><span class="token punctuation">[</span><span class="token punctuation">[</span>+-<span class="token operator">=</span><span class="token punctuation">]</span><span class="token punctuation">[</span>rwxX<span class="token punctuation">]</span><span class="token punctuation">..</span>.<span class="token punctuation">]</span><span class="token punctuation">[</span>,<span class="token punctuation">..</span>.<span class="token punctuation">]</span> <span class="token function">file</span>
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>u</code>: 表示该文件的拥有者。</li><li><code>g</code>: 表示与该文件的拥有者属于同组<code>group</code>的用户。</li><li><code>o</code>: 表示其他以外的人。</li><li><code>a</code>: 表示这三者皆是。</li><li><code>+</code>: 表示增加权限。</li><li><code>-</code>: 表示取消权限。</li><li><code>=</code>: 表示唯一设定权限。</li><li><code>r</code>: 表示可读取。</li><li><code>w</code>: 表示可写入。</li><li><code>x</code>: 表示可执行。</li><li><code>X</code>: 表示可执行当且仅当这个文件是个目录或者已经被设定过为可执行。</li><li><code>-c</code>或<code>--changes</code>: 效果类似<code>-v</code>参数，但仅回报更改的部分。</li><li><code>-f</code>或<code>--quiet</code>或<code>--silent</code>: 不显示错误信息。</li><li><code>-R</code>或<code>--recursive</code>: 递归处理，将指令目录下的所有文件及子目录一并处理。</li><li><code>-v</code>或<code>--verbose</code>: 显示指令执行过程。</li><li><code>--reference=&lt;folder/file&gt;</code>：把指定文件或目录的所属群组全部设成和参考文件或目录的所属群组相同。</li></ul><h2 id="权限" tabindex="-1"><a class="header-anchor" href="#权限" aria-hidden="true">#</a> 权限</h2><p>使用<code>ll</code>命令查看文件与文件夹相关信息，对于其权限信息:</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code>-rw-r--r--
</code></pre></div><p>首符号为<code>-</code>代表该文件为普通文件，为<code>d</code>则代表目录，紧接着三个字符<code>rw-</code>代表用户<code>u</code>权限属性，接下来三个字符<code>r--</code>代表用户组<code>g</code>权限属性，最后三个字符<code>r--</code>代表其他人<code>o</code>权限属性。</p><ul><li><code>r</code>: 读取属性，值为<code>4</code>。</li><li><code>w</code>: 写入属性，值为<code>2</code>。</li><li><code>x</code>: 执行属性，值为<code>1</code>。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>将文件<code>file.txt</code>设为所有人可读取。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> ugo+r file.txt
</code></pre></div><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> a+r file.txt
</code></pre></div><p>撤销组用户的对于<code>file.txt</code>的写入权限。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> g-w file.txt
</code></pre></div><p>将文件夹下所有目录与文件设为所有人可读取。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> <span class="token parameter variable">-R</span> a+r *
</code></pre></div><p>将文件<code>file.txt</code>设为拥有者有写权限，其他用户只有读权限。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> <span class="token assign-left variable">u</span><span class="token operator">=</span>rw,go<span class="token operator">=</span>r file.txt
</code></pre></div><p>将文件<code>file.py</code>设为拥有者有执行权限。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> u+x file.py
</code></pre></div><p>将文件<code>file.py</code>设为拥有者拥有所有权限，其他用户无任何权限。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> <span class="token number">700</span> file.py
</code></pre></div><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">chmod</span> <span class="token assign-left variable">u</span><span class="token operator">=</span>rwx,go<span class="token operator">=</span> file.py
</code></pre></div>`,26),d=[n];function l(t,p){return a(),c("div",null,d)}const u=e(o,[["render",l],["__file","chmod.html.vue"]]);export{u as default};
